// Java 25 exam prep - Nested classes
// Learn: compare static nested, inner, local, and anonymous class objects.
class Order {
    static class Summary { } // Static nested: no Order instance required.
    private final String id;
    private final int itemCount;
    Order(String id, int itemCount) { this.id = id; this.itemCount = itemCount; }
    class ItemView { String label() { return id + " has " + itemCount + " items"; } }
    void printAudit() {
        class AuditTask { String line() { return "audit " + id; } }
        Runnable async = new Runnable() { public void run() { System.out.println("async " + id); } };
        System.out.println(new ItemView().label());
        System.out.println(new AuditTask().line());
        async.run();
    }
}
